window.LEAF_SPINE_FONT_DATA_URLS = {
  regular: 'data:font/woff2;base64,',
  medium: 'data:font/woff2;base64,',
  semiBold: 'data:font/woff2;base64,',
  bold: 'data:font/woff2;base64,',
  extraBold: 'data:font/woff2;base64,',
  black: 'data:font/woff2;base64,'
};

(function injectPretendardFont() {
  const urls = window.LEAF_SPINE_FONT_DATA_URLS;
  if (!urls || document.getElementById("leaf-spine-font-face")) return;
  const weights = { regular: 400, medium: 500, semiBold: 600, bold: 700, extraBold: 800, black: 900 };
  const style = document.createElement("style");
  style.id = "leaf-spine-font-face";
  style.textContent = Object.keys(weights).map((key) => `@font-face{font-family:"Pretendard";src:url("${urls[key]}") format("woff2");font-weight:${weights[key]};font-style:normal;font-display:swap;}`).join("\n");
  document.head.appendChild(style);
})();
